import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Quote } from '../../data/models';

type StatusFilter = Quote['status'] | 'all';

@Component({
  selector: 'app-quotes',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './quotes.component.html',
  styleUrl: './quotes.component.css',
})
export class QuotesComponent {
  readonly statuses: Quote['status'][] = ['draft', 'submitted', 'won', 'lost'];
  readonly filter = signal<StatusFilter>('all');

  visibleQuotes = computed(() => {
    const f = this.filter();
    const list = this.seed.quotes();
    return f === 'all' ? list : list.filter((q) => q.status === f);
  });

  countByStatus = computed(() => {
    const counts: Record<string, number> = {};
    for (const s of this.statuses) counts[s] = 0;
    for (const q of this.seed.quotes()) counts[q.status] = (counts[q.status] ?? 0) + 1;
    return counts;
  });

  winRate = computed(() => {
    const won = this.countByStatus()['won'] ?? 0;
    const lost = this.countByStatus()['lost'] ?? 0;
    const decided = won + lost;
    return decided === 0 ? 0 : Math.round((won / decided) * 100);
  });

  totalQuoted = computed(() =>
    this.seed.quotes().reduce((sum, q) => sum + q.amount, 0),
  );

  openValue = computed(() =>
    this.seed.quotes()
      .filter((q) => q.status === 'draft' || q.status === 'submitted')
      .reduce((sum, q) => sum + q.amount, 0),
  );

  withIssues = computed(() =>
    this.seed.quotes().filter((q) => q.validationIssues > 0).length,
  );

  setFilter(f: StatusFilter): void {
    this.filter.set(f);
  }

  statusBadge(status: Quote['status']): string {
    switch (status) {
      case 'draft': return 'badge-neutral';
      case 'submitted': return 'badge-info';
      case 'won': return 'badge-success';
      case 'lost': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
